MAP
  NAME "guardian"
  EXTENT -180 -90 180 90
  IMAGETYPE png
  PROJECTION
    "init=epsg:4326"
  END

  WEB
    METADATA
      "wms_title" "Guardian WMS"
      "wms_onlineresource" "http://localhost:8081/?map=guardian&"
      "wms_srs" "EPSG:4326 EPSG:3857"
      "wms_enable_request" "*"
    END
  END

  LAYER
    NAME "ndvi"
    TYPE RASTER
    STATUS ON
    DATA "/data/ndvi.tif"

    PROCESSING "SCALE=-0.1,1.0"

    CLASS
      EXPRESSION ([pixel] >= 0 AND [pixel] < 0.2)
      STYLE
        COLOR 255 255 0
      END
    END

    CLASS
      EXPRESSION ([pixel] >= 0.2 AND [pixel] < 0.4)
      STYLE
        COLOR 255 165 0
      END
    END

    CLASS
      EXPRESSION ([pixel] >= 0.4 AND [pixel] < 0.6)
      STYLE
        COLOR 144 238 144
      END
    END

    CLASS
      EXPRESSION ([pixel] >= 0.6)
      STYLE
        COLOR 0 128 0
      END
    END

    PROJECTION
      "init=epsg:4326"
    END
    METADATA
      "wms_title" "NDVI"
      "wms_srs" "EPSG:4326 EPSG:3857"
    END
  END

END
